    func testOptionsPreprocessingAggressive() throws {
        // Aggressive preset removes nav, footer, aside unconditionally
        let _options = try HtmlToMarkdown.conversionOptionsFromJson("{\"preprocessing\":{\"preset\":\"Aggressive\"}}")
        let result = try HtmlToMarkdown.convert(html: "<nav>Menu</nav><article><h1>Title</h1><p>Content</p></article><aside>Sidebar</aside><footer>Footer</footer>", options: _options)
        XCTAssertTrue((result.content()?.toString() ?? "").contains("Title"), "expected to contain: \("Title")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("Content"), "expected to contain: \("Content")")
        XCTAssertFalse((result.content()?.toString() ?? "").contains("Menu"), "expected NOT to contain: \("Menu")")
    }

