    func testOptionsUrlEscapeStyleAngleDefault() throws {
        // Default angle style wraps URLs containing spaces in angle brackets
        let _options = try HtmlToMarkdown.conversionOptionsFromJson("{\"url_escape_style\":\"angle\"}")
        let result = try HtmlToMarkdown.convert(html: "<a href=\"/file (1).pdf\">file</a>", options: _options)
        XCTAssertTrue("</file (1).pdf>".isEmpty || (result.content()?.toString() ?? "").contains("</file (1).pdf>"), "expected to contain: \("</file (1).pdf>")")
    }

    func testOptionsUrlEscapeStylePercentAngleBracketsInUrl() throws {
        // Percent style encodes angle brackets in link URLs from issue 392
        let _options = try HtmlToMarkdown.conversionOptionsFromJson("{\"url_escape_style\":\"percent\"}")
        let result = try HtmlToMarkdown.convert(html: "<a href=\"/file (1) <draft>.pdf\">file</a>", options: _options)
        XCTAssertTrue("/file%20%281%29%20%3Cdraft%3E.pdf".isEmpty || (result.content()?.toString() ?? "").contains("/file%20%281%29%20%3Cdraft%3E.pdf"), "expected to contain: \("/file%20%281%29%20%3Cdraft%3E.pdf")")
    }

    func testOptionsUrlEscapeStylePercentImage() throws {
