        let _options = try HtmlToMarkdown.conversionOptionsFromJson("{\"url_escape_style\":\"percent\"}")
        let result = try HtmlToMarkdown.convert(html: "<img src=\"/img (1) <draft>.png\" alt=\"alt\">", options: _options)
        XCTAssertTrue("/img%20%281%29%20%3Cdraft%3E.png".isEmpty || (result.content()?.toString() ?? "").contains("/img%20%281%29%20%3Cdraft%3E.png"), "expected to contain: \("/img%20%281%29%20%3Cdraft%3E.png")")
    }

    func testOptionsUrlEscapeStylePercentLink() throws {
        // Percent style encodes spaces and parens in link URLs
        let _options = try HtmlToMarkdown.conversionOptionsFromJson("{\"url_escape_style\":\"percent\"}")
        let result = try HtmlToMarkdown.convert(html: "<a href=\"/file (1).pdf\">file</a>", options: _options)
        XCTAssertTrue("/file%20%281%29.pdf".isEmpty || (result.content()?.toString() ?? "").contains("/file%20%281%29.pdf"), "expected to contain: \("/file%20%281%29.pdf")")
        XCTAssertFalse((result.content()?.toString() ?? "").contains("</"), "expected NOT to contain: \("</")")
    }

    func testOptionsWhitespaceNormalized() throws {
        // Normalized whitespace mode collapses multiple spaces
        let _options = try HtmlToMarkdown.conversionOptionsFromJson("{\"whitespace_mode\":\"Normalized\"}")
        let result = try HtmlToMarkdown.convert(html: "<p>Text   with    extra   spaces.</p>", options: _options)
