        XCTAssertTrue((result.content()?.toString() ?? "").contains("Text"), "expected to contain: \("Text")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("with"), "expected to contain: \("with")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("extra"), "expected to contain: \("extra")")
        XCTAssertTrue((result.content()?.toString() ?? "").contains("spaces."), "expected to contain: \("spaces.")")
    }

